const payload = ($input.first().json.payload ?? $input.first().json);
const sql = String(payload.sql ?? '').trim();
const lower = sql.toLowerCase();
const blocked = ['insert ', 'update ', 'delete ', 'drop ', 'alter ', 'truncate ', 'grant ', 'revoke ', ';'].some(token => lower.includes(token));
if (!sql) return [{ json: { status: 'error', rows: [], summary: 'SQL is required' } }];
if (!lower.startsWith('select') || blocked) return [{ json: { status: 'pending_approval', rows: [], summary: 'Only safe single SELECT statements are allowed by default.', approval_required: true } }];
return [{ json: { status: 'success', rows: [], summary: 'SQL validated. Connect Postgres execution node with allowlist before production.', validated_sql: sql, parameters: payload.parameters ?? {} } }];
